def group_by_tags(items):
    groups = {}
    for item in items:
        tags = item['tags']
        if tags not in groups:
            groups[tags] = []
        groups[tags].append(item)
    return groups

import json

def parse_data(raw):
    try:
        return json.loads(raw)
    except:
        return None

def safe_convert(val):
    try:
        return int(val)
    except TypeError:
        return 0

def execute_task(success):
    try:
        if success:
            return True
        raise Exception('Failed')
    except Exception:
        pass
    finally:
